final:
module RefModule (
    input clk,
    input load,
    input [4:0] initial_value,
    output reg [4:0] count
);

    // 5-bit binary counter with loadable initial value logic
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (load) begin
            count <= initial_value;
        end else begin
            count <= count + 1;
        end
    end

endmodule
